INSERT INTO `choices` VALUES (1,'subject','เชิญประชุมปิดงบประจำปี','1. รับรองรายงานการประชุมครั้งที่ผ่านมา\r\n2. รายงานผลการดำเนินงานของบริษัทและรับรองงบการเงินประจำปี\r\n3. พิจารณาแต่งตั้งผู้สอบบัญชีและกำหนดค่าตอบแทนประจำปี\r\n4. พิจารณาแต่งตั้งคณะกรรมการแทนกรรมการที่จะครบกำหนดออกตามวาระ\r\n5. พิจารณาเงินปันผล การจัดสรรทุนสำรองตามกฎหมายและบำเหน็จกรรมการ\r\n6. พิจารณาเรื่องอื่นๆ (ถ้ามี)',7),(2,'subject','กำหนดรายละเอียดการประชุมเอง','กำหนดรายละเอียดการประชุมเอง',NULL),(3,'','เชิญประชุมย้ายที่อยู่','1. พิจารณาแก้ไขที่ตั้งสำนักงานของบริษัท\r\n2. พิจารณาแก้ไขเพิ่มเติมหนังสือบริคณห์สนธิ ข้อ 2. ดังนี้\r\nข้อ 2. สำนักงานของบริษัทตั้งอยู่ ณ จังหวัด .....\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(4,'','เชิญประชุมลดทุน','1. พิจารณาอนุมัติการลดทุนจดทะเบียนของบริษัท จำนวน ..... บาท\r\n2. พิจารณาแก้ไขเพิ่มเติมหนังสือบริคณห์สนธิ ข้อ 5. (ทุน) ดังนี้\r\nข้อ 5. ทุนของบริษัทกำหนดไว้เป็นจำนวน ..... บาท (.....) แบ่งออกเป็น ..... หุ้น (.....) มูลค่าหุ้นละ ..... บาท (.....)\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(5,'','เชิญประชุมเปลี่ยนกรรมการ','1. พิจารณาแต่งตั้งกรรมการและอำนาจกรรมการ\r\n',7),(6,'','เชิญประชุมเปลี่ยนชื่อบริษัท','1. พิจารณาแก้ไขเปลี่ยนแปลงชื่อของบริษัท\r\n2. พิจารณาแก้ไขเพิ่มเติมหนังสือบริคณห์สนธิ ข้อ 1. ดังนี้\r\nข้อ 1. ชื่อบริษัท ..... จำกัด\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(7,'','เชิญประชุมเพิ่มทุน','1. พิจารณาอนุมัติการเพิ่มทุนจดทะเบียนของบริษัท จำนวน ..... บาท\r\n2. พิจารณาแก้ไขเพิ่มเติมหนังสือบริคณห์สนธิ ข้อ 5. (ทุน) ดังนี้\r\nข้อ 5. ทุนของบริษัทกำหนดไว้เป็นจำนวน ..... บาท (.....) แบ่งออกเป็น ..... หุ้น (.....) มูลค่าหุ้นละ ..... บาท (.....)\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(8,'','เชิญประชุมเพิ่มวัตถุประสงค์','1. พิจารณาแก้ไขเพิ่มเติมวัตถุประสงค์ของบริษัท\r\n2. พิจารณาแก้ไขเพิ่มเติมหนังสือบริคณห์สนธิ ข้อ 3. ดังนี้\r\nข้อ 3. วัตถุประสงค์ทั้งหลายของบริษัทมี 29 ข้อ ดังปรากฎในแบบ ว. ที่แนบ\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(9,'','ประชุมเลิกบริษัท','1. พิจารณาลงมติพิเศษเรื่องการเลิกบริษัท\r\n2. พิจารณาแต่งตั้งผู้ชำระบัญชี\r\n3. พิจารณาแต่งตั้งผู้สอบบัญชี (ถ้ามี)\r\n4. พิจารณาเรื่องอื่นๆ (ถ้ามี)',7),(10,'','เชิญประชุมเสร็จชำระบัญชี','1. รับรองรายงานการประชุมวิสามัญผู้ถือหุ้นครั้งที่ .....\r\n2. พิจารณารายงานการชำระบัญชี\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',7),(11,'','เชิญประชุมแก้ไขเพิ่มเติมตราบริษัท','1. พิจารณาแก้ไขเพิ่มเติมตราของบริษัท\r\n2. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(12,'','เชิญประชุมอนุมัติเงินปันผล','1. รับรองรายงานการประชุมครั้งที่ผ่านมา\r\n2. พิจารณาการอนุมัติการจ่ายเงินปันผลของบริษัท\r\n3. พิจารณาเรื่องอื่นๆ (ถ้ามี)',7),(13,'','เชิญประชุมแก้ไขข้อบังคับ','1. พิจารณาแก้ไขเพิ่มเติมข้อบังคับ\r\n2. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14),(15,'','เชิญประชุมควบรวมบริษัท','1. พิจารณาการควบบริษัทจำกัด\r\n2. พิจารณาเรื่องอื่นๆ (ถ้ามี)',14);
/*!40000 ALTER TABLE `choices` ENABLE KEYS */;
