INSERT INTO `placard` VALUES (22,'smith@mac.in.th','On','เชิญประชุมปิดงบประจำปี','1. รับรองรายงานการประชุมครั้งที่ผ่านมา\r\n2. รายงานผลการดำเนินงานของบริษัทและรับรองงบการเงินประจำปี\r\n3. พิจารณาแต่งตั้งผู้สอบบัญชีและกำหนดค่าตอบแทนประจำปี\r\n4. พิจารณาแต่งตั้งคณะกรรมการแทนกรรมการที่จะครบกำหนดออกตามวาระ\r\n5. พิจารณาเงินปันผล การจัดสรรทุนสำรองตามกฎหมายและบำเหน็จกรรมการ\r\n6. พิจารณาเรื่องอื่นๆ (ถ้ามี)','บริษัท ACME จำกัด','2/2563','ท่านผู้ถือหุ้นของบริษัท','2021-03-26','10:30:00','ที่สำนักงานใหญ่','2021-03-18','นาย','สมชาย กล้าหาญ','กรรมการผู้มีอำนาจลงนาม',NULL,NULL,NULL,NULL,NULL),(23,'vnnbizs@gmail.com','On','เชิญประชุมปิดงบประจำปี','1. รับรองรายงานการประชุมครั้งที่ผ่านมา\r\n2. รายงานผลการดำเนินงานของบริษัทและรับรองงบการเงินประจำปี\r\n3. พิจารณาแต่งตั้งผู้สอบบัญชีและกำหนดค่าตอบแทนประจำปี\r\n4. พิจารณาแต่งตั้งคณะกรรมการแทนกรรมการที่จะครบกำหนดออกตามวาระ\r\n5. พิจารณาเงินปันผล การจัดสรรทุนสำรองตามกฎหมายและบำเหน็จกรรมการ\r\n6. พิจารณาเรื่องอื่นๆ (ถ้ามี)','บริษัท อะโทมี่ กรุงเทพฯ พาราไดซ์ จำกัด','1/2564','ท่านผู้ถือหุ้นของบริษัท','2021-01-27','10:30:00','1052 ถนนสนามบิน ต.เวียง อ.เมืองเชียงราย จ.เชียงราย','2021-01-19','นาย','ชัยวัฒน์ ชินเมธีพิทักษ์','กรรมการผู้มีอำนาจลงนาม',NULL,NULL,NULL,NULL,NULL),(24,'vnnbizs@gmail.com','On','เชิญประชุมปิดงบประจำปี','1. รับรองรายงานการประชุมครั้งที่ผ่านมา\r\n2. รายงานผลการดำเนินงานของบริษัทและรับรองงบการเงินประจำปี\r\n3. พิจารณาแต่งตั้งผู้สอบบัญชีและกำหนดค่าตอบแทนประจำปี\r\n4. พิจารณาแต่งตั้งคณะกรรมการแทนกรรมการที่จะครบกำหนดออกตามวาระ\r\n5. พิจารณาเงินปันผล การจัดสรรทุนสำรองตามกฎหมายและบำเหน็จกรรมการ\r\n6. พิจารณาเรื่องอื่นๆ (ถ้ามี)','บริษัท เอสเคเอ็น การบัญชีและที่ปรึกษา จำกัด','1/2564','ท่านผู้ถือหุ้นของบริษัท','2021-01-28','10:30:00','32/204 หมู่ 1 ซอยแจ้งวัฒนะ 43 ถนนแจ้งวัฒนะ ต.คลองเกลือ\r\nอ.ปากเกร็ด จ.นนทบุรี 11120','2021-01-20','นาย','ศุภฤกษ์ กาฬกาญจน์','กรรมการผู้มีอำนาจลงนาม',NULL,NULL,NULL,NULL,NULL),(25,'salifa@gmail.com','On','เชิญประชุมเพิ่มทุน','1. พิจารณาอนุมัติการเพิ่มทุนจดทะเบียนของบริษัท จาก 12 ล้านบาท เป็นจำนวน 25ล